using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents (e.g. "Blog|1") are still found.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");
        modelBuilder.Entity<Blog>()
            .UsePropertyAccessMode(PropertyAccessMode.Property);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id");
        modelBuilder.Entity<Blog>()
            .HasKey(b => b.Id);

        // Use the legacy id format: "EntityType|KeyValue"
        modelBuilder.Entity<Blog>().Metadata
            .SetDiscriminatorMappingComplete(false);

        // Breaking change 3: HasIndex now throws for Cosmos.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
        // Cosmos does not support secondary indexes via EF Core.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

