using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Fix 1 – Discriminator property renamed from "Discriminator" to "$type".
            //   Keep the old name so existing documents are still found.
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2 – JSON "id" no longer includes discriminator (was "Blog|1", now just "1").
            //   Restore the old format so existing documents are still matched.
            b.HasDiscriminatorInJsonId();

            // Fix 3 – JSON "id" is now mapped directly to the CLR key property;
            //   the old shadow __id property was removed, so "Id" is no longer
            //   persisted as a separate JSON property. Use HasShadowId() to
            //   restore the old __id shadow property and keep "Id" in the document.
            b.HasShadowId();

            // Fix 4 – HasIndex now throws for Cosmos (was silently ignored).
            //   REMOVED: b.HasIndex(e => e.Name);
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

